import React, { useEffect, useState } from "react";
import Loader from "react-loaders";
import "./index.scss";
import AnimatedLetters from "../AnimatedLetters";
import { useNavigate } from "react-router-dom";

const Search = () => {
    const [letterClass, setLetterClass] = useState('text-animate');
    const [searchQuery, setSearchQuery] = useState('');
    const navigate = useNavigate();
    const quickSearches = ["Bellingham", "Lewandowski", "Vinicius", "Courtois"];

    useEffect(() => {
        const timer = setTimeout(() => {
            setLetterClass("text-animate-hover");
        }, 3000); 

        return () => { 
            clearTimeout(timer);
        }
    }, []);

    const handleSearchChange = event => {
        setSearchQuery(event.target.value);
    };

    const handleGoButtonClick = () => {
        if (!searchQuery.trim()) {
            return;
        }
        navigate(`/data?name=${encodeURIComponent(searchQuery)}`);
    };

    return (
        <>
            <div className="container teams-page">
                <h1 className="page-title">
                    <br/>
                    <br/>
                    <AnimatedLetters letterClass={letterClass} strArray={"Search".split("")} idx={15}/>
                </h1>
                <div className="search-bar">
                    <input
                        type="text"
                        placeholder="Search for players"
                        value={searchQuery}
                        onChange={handleSearchChange}
                    />
                    <button onClick={handleGoButtonClick}>Go</button>
                </div>
                <div className="quick-searches">
                    {quickSearches.map((name) => (
                        <button key={name} onClick={() => navigate(`/data?name=${encodeURIComponent(name)}`)}>
                            {name}
                        </button>
                    ))}
                </div>
            </div>
            <Loader type="pacman"/>
        </>
    );
}

export default Search;
